@page "/privacy"
@attribute [RenderModeAttribute(0)]
@using Microsoft.AspNetCore.Http
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This application uses cookies to improve your experience.
    We collect only the data necessary to provide our services.
</p>

<h2>Cookie Consent</h2>

@if (_hasConsent)
{
    <div class="alert alert-success">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

<h2>What We Collect</h2>
<ul>
    <li>Essential cookies required for the application to function</li>
    <li>Preference cookies to remember your settings</li>
</ul>

<h2>Your Rights</h2>
<p>
    You may withdraw consent at any time by clearing your browser cookies.
</p>

@code {
    private bool _hasConsent;

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            _hasConsent = httpContext.Request.Cookies.ContainsKey("consent");
        }
    }
}

using Microsoft.AspNetCore.Components;

namespace BlazorApp.Components.Pages;

// Forces this page to render statically (no interactive render mode)
// so that HttpContext is available during SSR.
[AttributeUsage(AttributeTargets.Class)]
public class RenderModeAttribute : Attribute
{
    // A marker attribute isn't strictly needed if using the @rendermode directive,
    // but this file exists to document the intent. The actual opt-out is done via
    // the @attribute directive in the .razor file combined with App.razor logic.
}

