{"path": "/tmp/sv-4a38a264fbb640929ed87e95457d9fa5/Components/App.razor", "file_text": "<!DOCTYPE html>
<html lang="en">

<head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <base href="/" />
    <link rel="stylesheet" href="css/app.css" />
    <HeadOutlet @rendermode="PageRenderMode" />
</head>

<body>
    <Routes @rendermode="PageRenderMode" />

    <script src="_framework/blazor.web.js"></script>
</body>

</html>

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private IComponentRenderMode? PageRenderMode =>
        AssignRenderMode(HttpContext);

    private static IComponentRenderMode? AssignRenderMode(HttpContext? httpContext)
    {
        // Pages that need static SSR (e.g., to access HttpContext) opt out of
        // interactive rendering by declaring @attribute [RenderModeAttribute(0)].
        // We detect the target page from the endpoint metadata and return null
        // (static SSR) for those pages, while all others get InteractiveServer.

        var endpoint = httpContext?.GetEndpoint();
        if (endpoint is not null)
        {
            var metadata = endpoint.Metadata.GetMetadata<ComponentTypeMetadata>();
            if (metadata is not null)
            {
                var pageType = metadata.Type;
                var hasStaticAttribute = pageType
                    .GetCustomAttributes(typeof(BlazorApp.Components.Pages.RenderModeAttribute), false)
                    .Length > 0;

                if (hasStaticAttribute)
                {
                    return null; // Static SSR — HttpContext is available
                }
            }
        }

        return Microsoft.AspNetCore.Components.Web.RenderMode.InteractiveServer;
    }
}
"}

